// checkPrereqs verifies the local toolchain and /dev/kvm access.
func (p *Provider) checkPrereqs() error {
	required := map[string]string{
		"virsh":        "virsh not found: install libvirt (sudo apt install libvirt-daemon-system)",
		"virt-install": "virt-install not found: install virtinst (sudo apt install virtinst)",
		"qemu-img":     "qemu-img not found: install qemu-utils (sudo apt install qemu-utils)",
	}
	for bin, msg := range required {
		if _, err := exec.LookPath(bin); err != nil {
			return fmt.Errorf("%s", msg)
		}
	}
	if detectISOTool() == isoNone {
		return fmt.Errorf("neither cloud-localds nor genisoimage found: install cloud-image-utils or genisoimage")
	}
	if _, err := os.Stat("/dev/kvm"); err != nil {
		return fmt.Errorf("/dev/kvm not accessible: check that the current user is in the 'kvm' group")
	}
	return nil
}

