	$(eval VM_NETWORK := $(shell sudo virsh net-dumpxml default 2>/dev/null \
	    | python3 -c "import sys, re, ipaddress; \
	      xml = sys.stdin.read(); \
	      m = re.search(r\"<ip address='([0-9.]+)' netmask='([0-9.]+)'\", xml); \
	      print(str(ipaddress.ip_network((m.group(1).rsplit('.',1)[0]+'.0')+'/'+m.group(2), strict=False))) if m else print('')" 2>/dev/null || echo ""))
	@if [ -z "$(VM_NETWORK)" ]; then \
	    echo "Could not detect libvirt default network. Start libvirtd first, or pass it manually:"; \
	    echo "  sudo ufw allow from <VM_NETWORK> to any port nfs"; \
	    echo "  sudo ufw allow from <VM_NETWORK> to any port 111"; \
	else \
	    sudo ufw allow from $(VM_NETWORK) to any port nfs; \
	    sudo ufw allow from $(VM_NETWORK) to any port 111; \
	    sudo ufw reload; \
	    echo "ufw rules added for $(VM_NETWORK)"; \
	fi

